import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const prompt = `Act as a master philologist. Analyze "${query}" from ${sourceLanguage} to ${targetLanguage}.

Tone: Calm, minimal, scholarly but accessible.
Scope: Top 5,000 frequent words focus.

Provide a JSON dictionary entry including:
1. term: The lemma.
2. mainTranslation: Primary everyday equivalent.
3. sourceLevel: CEFR (A1-C2).
4. philology: { etymology (1 clear sentence), partOfSpeech, gender/plural (if DE) }.
5. culture: { usage (short clear definition), register (formal/informal/neutral), notes (sociolinguistic) }.
6. synonyms: 3-5 source language context words.
7. variations: Target language equivalents with confidence.
8. literature: Two examples: a) Famous/Cultural quote + translation, b) Simple daily sentence + translation.
9. idioms: 1-2 common fixed expressions.

Rules:
- German: include gender/plural.
- Uzbek: modern Latin script.
- Return ONLY JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          sourceLevel: { 
            type: Type.STRING, 
            description: "The CEFR level of the word (A1, A2, B1, B2, C1, C2)." 
          },
          philology: {
            type: Type.OBJECT,
            properties: {
              etymology: { type: Type.STRING },
              historicalNotes: { type: Type.STRING },
              inflectionNotes: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING },
              plural: { type: Type.STRING }
            },
            required: ["etymology", "partOfSpeech"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              usage: { type: Type.STRING },
              register: { type: Type.STRING, enum: ['formal', 'informal', 'neutral'] },
              notes: { type: Type.STRING }
            },
            required: ["usage", "register", "notes"]
          },
          synonyms: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Synonyms in the source language."
          },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER },
                source: { type: Type.STRING, enum: ['ai'] }
              }
            }
          },
          literature: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                explanation: { type: Type.STRING },
                type: { type: Type.STRING, enum: ['greeting', 'proverb', 'historical', 'general'] }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "sourceLevel", "philology", "culture", "synonyms", "variations", "literature", "idioms"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: crypto.randomUUID(),
    term: rawData.term || query,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel,
    philology: rawData.philology,
    culture: rawData.culture,
    synonyms: rawData.synonyms || [],
    variations: rawData.variations || [],
    literature: rawData.literature || [],
    idioms: rawData.idioms || [],
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const context = entries.map(e => `${e.term} (Translation: ${e.mainTranslation}, Langs: ${e.sourceLang} to ${e.targetLang})`).join("; ");

  const prompt = `For each of the following word pairs, generate exactly TWO simple multiple-choice questions:
1. One question asking for the translation of the source word into the target language.
2. One question asking for the reverse translation of the target word back into the source language.

Context: ${context}

Question format:
- The question should just be the word itself (e.g., "Tag" or "Kun").
- Provide 3-4 single-word options.
- Ensure the options are plausible but distinct.

Return a JSON array of objects.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
}

export type Language = 'German' | 'Uzbek' | 'English' | 'Russian';

export interface SemanticVariation {
  text: string;
  confidence: number;
  source: 'human' | 'ai';
}

export interface LiteraryReference {
  text: string;
  translation?: string;
  source: string;
  author?: string;
}

export interface Idiom {
  text: string;
  translation: string;
  explanation: string;
  type: 'greeting' | 'proverb' | 'historical' | 'general';
}

export interface LexicalEntry {
  id: string;
  term: string; // The specific form searched (e.g., "guten")
  lemma?: string; // The dictionary base form (e.g., "gut")
  inflection?: string; // Description of the form (e.g., "Accusative Masculine")
  normalizedTerm: string;
  mainTranslation: string;
  sourceLang: Language;
  targetLang: Language;
  sourceLevel?: string;
  targetLevel?: string;

  // 🔬 Philological Analysis
  philology: {
    etymology: string;
    historicalNotes?: string;
    inflectionNotes?: string;
    partOfSpeech: string;
    gender?: string;
    plural?: string;
  };

  // 🌍 Cultural / Language Context
  culture: {
    usage: string;
    register: 'formal' | 'informal' | 'neutral';
    notes: string;
  };

  // 📖 Lexical Relations
  synonyms: string[];

  // 🔁 Semantic Variations (Target Language)
  variations: SemanticVariation[];

  // 📚 Literary Manifestations
  literature: LiteraryReference[];

  // 🗣 Idioms & Fixed Expressions
  idioms: Idiom[];

  timestamp: number;
  isPreinstalled?: boolean;
}

export interface UserProfile {
  username: string;
  xp: number;
  rank: string;
  searchCount: number;
  arenaWins: number;
  accuracy: number;
  streak: number;
}

