import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { fetchProfile, fetchHistory, upsertProfile, saveHistoryEntry } from './services/supabase';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'synced' | 'syncing' | 'offline'>('syncing');

  const [deviceId] = useState(() => {
    let id = localStorage.getItem('lexDeviceId');
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem('lexDeviceId', id);
    }
    return id;
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  useEffect(() => {
    const hydrate = async () => {
      setSyncStatus('syncing');
      try {
        const [cloudProfile, cloudHistory] = await Promise.all([
          fetchProfile(deviceId),
          fetchHistory(deviceId)
        ]);

        if (cloudProfile) setProfile(cloudProfile);
        if (cloudHistory && cloudHistory.length > 0) setHistory(cloudHistory);

        setSyncStatus('synced');
      } catch (err) {
        console.error("Supabase Hydration Error:", err);
        setSyncStatus('offline');
      } finally {
        setIsLoading(false);
      }
    };

    hydrate();

    if ((window as any).Telegram?.WebApp) {
      const tg = (window as any).Telegram.WebApp;
      tg.ready();
      tg.expand();
    }
  }, [deviceId]);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    setSyncStatus('syncing');
    try {
      await upsertProfile(deviceId, newProfile);
      setSyncStatus('synced');
    } catch {
      setSyncStatus('offline');
    }
  }, [deviceId]);

  const addEntry = async (entry: LexicalEntry) => {
    // Unique check on term to prevent duplicates in local state
    const newHistory = [entry, ...history.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase())].slice(0, 50);
    setHistory(newHistory);

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    try {
      await Promise.all([
        saveHistoryEntry(deviceId, entry),
        syncProfile(newProfile)
      ]);
    } catch (e) {
      console.warn("Cloud sync deferred.");
    }
  };

  const handleArenaResult = async (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = (correctCount / totalQuestions) * 100;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  const navigateToDictionary = () => {
    setActiveEntry(null);
    setMode(AppMode.DICTIONARY);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#fcfcfb] flex flex-col items-center justify-center">
        <div className="text-6xl serif font-black tracking-tighter text-[#7c1a1a] animate-pulse mb-4">LEX.</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col">
      <header className="px-6 md:px-12 py-10 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-6">
          <span onClick={navigateToDictionary} className="text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform">LEX.</span>
          <div className="h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.5em] text-stone-900 font-black leading-none mb-1">The Polyglot Insight Engine</span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">Archival philology & context</span>
          </div>
        </div>

        <nav className="flex items-center gap-10 text-[10px] uppercase tracking-[0.3em] font-black text-stone-400">
          <button onClick={navigateToDictionary} className={`border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}>Encyclopedia</button>
          <button onClick={() => setMode(AppMode.ARENA)} className={`border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}>The Arena</button>
          <button onClick={() => setMode(AppMode.ARCHIVE)} className={`border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}>Chronicles</button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}
          {mode === AppMode.ARENA && <Arena history={history} onResult={handleArenaResult} />}
          {mode === AppMode.ARCHIVE && <Archive history={history} onEntryClick={handleHistoryItemClick} />}
        </div>
      </main>

      <footer className="py-12 border-t border-stone-100 bg-white/50 px-12">
        <div className="max-w-[1400px] mx-auto flex flex-col md:flex-row justify-between items-center gap-6 text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-4">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className={`flex items-center gap-1.5 ${syncStatus === 'synced' ? 'text-green-600' : 'text-amber-500'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${syncStatus === 'synced' ? 'bg-green-500' : 'bg-amber-500 animate-pulse'}`}></span>
                {syncStatus.toUpperCase()} CLOUD
             </span>
          </div>
          <div className="flex items-center gap-8">
            <span className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-[#7c1a1a]"></span>{profile.rank}</span>
            <span className="text-stone-900">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const prompt = `Act as a master philologist and lexicographer. 
Analyze the specific word form: "${query}" 
From: ${sourceLanguage} 
To: ${targetLanguage}

CRITICAL INSTRUCTION:
1. 'term' MUST be the exact word I provided: "${query}". Do NOT change it to the base form.
2. 'lemma' MUST be the dictionary base form (e.g., if query is "guten", lemma is "gut").
3. 'inflection' MUST describe why "${query}" differs from the lemma (e.g., "Accusative Masculine Singular").
4. If "${query}" is already the base form, 'lemma' and 'term' will be the same and 'inflection' can be "base form" or "nominative".

Provide a JSON dictionary entry:
- term: "${query}"
- lemma: (The dictionary headword)
- inflection: (Grammatical analysis of this specific form)
- mainTranslation: Primary equivalent in ${targetLanguage} for this specific context.
- sourceLevel: CEFR level (A1-C2).
- philology: { etymology, partOfSpeech, gender, plural }.
- culture: { usage, register, notes }.
- synonyms, variations, literature, idioms.

Return ONLY valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          lemma: { type: Type.STRING },
          inflection: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          sourceLevel: { type: Type.STRING },
          philology: {
            type: Type.OBJECT,
            properties: {
              etymology: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING },
              plural: { type: Type.STRING }
            },
            required: ["etymology", "partOfSpeech"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              usage: { type: Type.STRING },
              register: { type: Type.STRING, enum: ['formal', 'informal', 'neutral'] },
              notes: { type: Type.STRING }
            },
            required: ["usage", "register", "notes"]
          },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER },
                source: { type: Type.STRING, enum: ['ai'] }
              }
            }
          },
          literature: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                explanation: { type: Type.STRING },
                type: { type: Type.STRING }
              }
            }
          }
        },
        required: ["term", "lemma", "mainTranslation", "sourceLevel", "philology", "culture", "synonyms", "variations", "literature", "idioms"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: crypto.randomUUID(),
    term: rawData.term || query,
    lemma: rawData.lemma,
    inflection: rawData.inflection,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel,
    philology: rawData.philology,
    culture: rawData.culture,
    synonyms: rawData.synonyms || [],
    variations: rawData.variations || [],
    literature: rawData.literature || [],
    idioms: rawData.idioms || [],
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const context = entries.map(e => `${e.term} (Translation: ${e.mainTranslation})`).join("; ");
  const prompt = `Generate 2 multiple-choice questions for each: ${context}. Return JSON array.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            explanation: { type: Type.STRING }
          }
        }
      }
    }
  });
  return JSON.parse(response.text || '[]');
}

