export const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Circuit breakers to prevent spamming logs if tables are missing
const missingTables = new Set<string>();

const handleSupabaseError = (error: any, tableName: string) => {
  if (error?.code === 'PGRST205') {
    if (!missingTables.has(tableName)) {
      console.warn(`Supabase Table '${tableName}' is missing. Cloud sync disabled for this session. Please run the provided SQL setup.`);
      missingTables.add(tableName);
    }
    return true; // Handled
  }
  return false;
};

/**
 * SQL SETUP (Run in Supabase SQL Editor):
 * 
 * CREATE TABLE lex_profiles (
 *   user_id TEXT PRIMARY KEY,
 *   profile_json JSONB NOT NULL,
 *   updated_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * 
 * CREATE TABLE lex_history (
 *   id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
 *   user_id TEXT NOT NULL,
 *   term TEXT NOT NULL,
 *   entry_json JSONB NOT NULL,
 *   timestamp BIGINT NOT NULL,
 *   UNIQUE(user_id, term)
 * );
 */

export async function fetchProfile(userId: string): Promise<UserProfile | null> {
  if (missingTables.has('lex_profiles')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_profiles')
      .select('profile_json')
      .eq('user_id', userId)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_profiles');
      return null;
    }
    return data?.profile_json as UserProfile || null;
  } catch (err) {
    return null;
  }
}

export async function upsertProfile(userId: string, profile: UserProfile) {
  if (missingTables.has('lex_profiles')) return;
  try {
    const { error } = await supabase
      .from('lex_profiles')
      .upsert({ 
        user_id: userId, 
        profile_json: profile, 
        updated_at: new Date().toISOString() 
      }, { onConflict: 'user_id' });

    if (error) handleSupabaseError(error, 'lex_profiles');
  } catch (err) {}
}

export async function fetchHistory(userId: string): Promise<LexicalEntry[]> {
  if (missingTables.has('lex_history')) return [];
  try {
    const { data, error } = await supabase
      .from('lex_history')
      .select('entry_json')
      .eq('user_id', userId)
      .order('timestamp', { ascending: false })
      .limit(50);

    if (error) {
      handleSupabaseError(error, 'lex_history');
      return [];
    }
    return data?.map(item => item.entry_json as LexicalEntry) || [];
  } catch (err) {
    return [];
  }
}

export async function saveHistoryEntry(userId: string, entry: LexicalEntry) {
  if (missingTables.has('lex_history')) return;
  try {
    const { error } = await supabase
      .from('lex_history')
      .upsert({
        user_id: userId,
        term: entry.term,
        entry_json: entry,
        timestamp: entry.timestamp
      }, { onConflict: 'user_id, term' });

    if (error) handleSupabaseError(error, 'lex_history');
  } catch (err) {}
}

import React, { useState, useMemo, useEffect } from 'react';
