    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  // Handle Dynamic Suggestions Update
  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        // 1. Fetch from Local History
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }))
          .slice(0, 3);

        // 2. Fetch from Seed Archive
        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }))
          .slice(0, 2);

        // 3. Fetch from Supabase Global Cache
        const globalTerms = await fetchSuggestions(query, sourceLang);
        const globalMatches = globalTerms
          .filter(term => !localMatches.some(m => m.term.toLowerCase() === term.toLowerCase()))
          .map(term => ({ term, source: 'global' as const }));

        // Combine and prioritize: Local > Seed > Global
        const combined = [...localMatches, ...seedMatches, ...globalMatches].slice(0, 8);

        // Remove duplicates
        const unique = combined.filter((v, i, a) => a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 200); // Efficient delay
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = (lang: Language) => {
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    if (autoAudio) speak(cleanQuery, sourceLang);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      setQuery(localHit.term);
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        setQuery(globalHit.term);
        onEntrySaved(globalHit);
        setLoading(false);
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      setQuery(finalEntry.term);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = () => {
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-8 md:space-y-12 max-w-7xl mx-auto">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="space-y-2 border-l-[3px] border-[#7c1a1a] pl-6 hidden sm:block">
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
          <div className="flex items-baseline gap-3">
            <span className="text-4xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-300 font-bold">Total XP Earned</span>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-4 bg-stone-50/50 px-4 py-2 rounded-full border border-stone-100">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">Auto-pronounce</span>
            <button onClick={() => setAutoAudio(!autoAudio)} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-0.5 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-4 h-4 bg-white rounded-full transition-all shadow-sm ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      {/* Search Input & Suggestions */}
      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className="bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[120px]">
            <div className="flex-1 flex items-center px-4 md:px-10">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
                onKeyDown={handleKeyDown}
                placeholder="Summon an inscription..."
                className="w-full text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase font-medium tracking-tighter leading-none" 
              />
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-4 md:px-10 text-stone-300 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-6 h-6 md:w-12 md:h-12 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-14 md:h-14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-300 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-6 md:px-10 py-4 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-colors ${selectedIndex === idx ? 'bg-stone-50 border-l-[4px] border-l-[#7c1a1a]' : 'border-l-[4px] border-l-transparent'}`}
               >
                 <div className="flex items-center gap-4">
                    {s.source === 'local' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-[#7c1a1a]"><path d="M12 2v10l4.5 4.5"/><circle cx="12" cy="12" r="10"/></svg>
                    )}
                    {s.source === 'seed' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-stone-400"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1-2.5-2.5Z"/><path d="M8 7h6"/><path d="M8 11h8"/></svg>
                    )}
                    {s.source === 'global' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-stone-300"><circle cx="12" cy="12" r="10"/><path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"/><path d="M2 12h20"/></svg>
                    )}
                    <span className={`serif text-lg md:text-xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 </div>
                 <span className="text-[8px] md:text-[10px] uppercase tracking-widest text-stone-300 font-black group-hover:text-stone-400 transition-colors">
                   {s.source === 'local' ? 'Personal Memory' : s.source === 'seed' ? 'Lexicon Scribe' : 'Global Archive'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[50px]">
        {loading && <div className="bg-white border border-stone-100 p-8 md:p-12 animate-pulse space-y-12 rounded-sm"><div className="h-12 w-48 bg-stone-50" /></div>}
        {result && !loading && <ResultCard entry={result} />}
      </div>

      {/* Footer History Section */}
      <div className="pt-16 md:pt-24 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[3px] border-[#7c1a1a] pl-6 md:pl-8 py-1">
            <h2 className="text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[9px] uppercase tracking-[0.1em] font-medium">Recently unearthed insights</p>
          </div>
          <button onClick={onStartArena} className="group relative bg-[#7c1a1a] text-white px-8 md:px-10 py-4 flex items-center gap-4 shadow-lg hover:shadow-[#7c1a1a]/20 hover:-translate-y-1 transition-all rounded-sm w-full sm:w-auto justify-center">
            <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.4em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

