import { createClient } from '@supabase/supabase-js';
import { LexicalEntry, UserProfile, Language } from '../types';

/**
 * MANDATORY SQL SETUP (Run this in your Supabase SQL Editor):
 * 
 * -- 1. Global Cache Table
 * CREATE TABLE IF NOT EXISTS lex_entries (
 *   id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
 *   term TEXT NOT NULL,
 *   normalized_term TEXT NOT NULL,
 *   source_lang TEXT NOT NULL,
 *   target_lang TEXT NOT NULL,
 *   entry_data JSONB NOT NULL,
 *   created_at TIMESTAMPTZ DEFAULT NOW(),
 *   UNIQUE(normalized_term, source_lang, target_lang)
 * );
 * 
 * -- 2. User Profiles Table
 * CREATE TABLE IF NOT EXISTS lex_profiles (
 *   device_id TEXT PRIMARY KEY,
 *   profile_data JSONB NOT NULL,
 *   updated_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * 
 * -- 3. Performance Index
 * CREATE INDEX IF NOT EXISTS idx_lex_entries_lookup ON lex_entries (normalized_term, source_lang);
 * CREATE INDEX IF NOT EXISTS idx_lex_entries_recent ON lex_entries (created_at DESC);
 */

const supabaseUrl = 'https://pfykbgifzgfgeuiadebm.supabase.co';
const supabaseAnonKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBmeWtiZ2lmemdmZ2V1aWFkZWJtIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc0NTY5ODMsImV4cCI6MjA4MzAzMjk4M30.tSh8OgqVw3yk4JgCs7jzz21SJLKaotce_8AVAJdi9Z0';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

const missingTables = new Set<string>();

const handleSupabaseError = (error: any, tableName: string) => {
  if (error?.code === 'PGRST205' || error?.status === 404) {
    if (!missingTables.has(tableName)) {
      console.warn(`Supabase Table '${tableName}' not found. Please run the SQL schema setup provided in services/supabase.ts.`);
      missingTables.add(tableName);
    }
    return true;
  }
  return false;
};

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  if (missingTables.has('lex_entries') || query.length < 2) return [];
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${query.toLowerCase().trim()}%`)
      .order('created_at', { ascending: false }) // Recency ranking: newest community finds first
      .limit(15);

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return [];
    }
    return Array.from(new Set(data?.map(d => d.term) || []));
  } catch {
    return [];
  }
}

export async function fetchGlobalEntry(
  normalizedTerm: string,
  sourceLang: Language,
  targetLang: Language
): Promise<LexicalEntry | null> {
  if (missingTables.has('lex_entries')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return null;
    }
    return data?.entry_data as LexicalEntry || null;
  } catch {
    return null;
  }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  if (missingTables.has('lex_entries')) return;
  try {
    await supabase
      .from('lex_entries')
      .upsert({
        term: entry.term,
        normalized_term: entry.normalizedTerm,
        source_lang: entry.sourceLang,
        target_lang: entry.targetLang,
        entry_data: entry
      }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

export async function fetchProfile(deviceId: string): Promise<UserProfile | null> {
  if (missingTables.has('lex_profiles')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_profiles')
      .select('profile_data')
      .eq('device_id', deviceId)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_profiles');
      return null;
    }
    return data?.profile_data as UserProfile || null;
  } catch {
    return null;
  }
}

export async function upsertProfile(deviceId: string, profile: UserProfile) {
  if (missingTables.has('lex_profiles')) return;
  try {
    await supabase
      .from('lex_profiles')
      .upsert({ 
        device_id: deviceId, 
        profile_data: profile, 
        updated_at: new Date().toISOString() 
      }, { onConflict: 'device_id' });
  } catch {}
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  // Handle Dynamic Suggestions Update with Hybrid Ranking
  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        // 1. Fetch from Local History
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        // 2. Fetch from Seed Archive
        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        // 3. Fetch from Supabase Global Archive
        const globalTerms = await fetchSuggestions(query, sourceLang);
        const globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));

        // Combine with specific quota to ensure Global visibility
        // Logic: 3 Local, 2 Seed, up to 5 Global
        const combined = [
          ...localMatches.slice(0, 3),
          ...seedMatches.slice(0, 2),
          ...globalMatches.filter(gm => !localMatches.some(lm => lm.term.toLowerCase() === gm.term.toLowerCase()))
        ].slice(0, 10);

        // Final unique check
        const unique = combined.filter((v, i, a) => a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150); // Faster update
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = (lang: Language) => {
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    if (autoAudio) speak(cleanQuery, sourceLang);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      setQuery(localHit.term);
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        setQuery(globalHit.term);
        onEntrySaved(globalHit);
        setLoading(false);
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      setQuery(finalEntry.term);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = () => {
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-8 md:space-y-12 max-w-7xl mx-auto">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="space-y-2 border-l-[3px] border-[#7c1a1a] pl-6 hidden sm:block">
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
          <div className="flex items-baseline gap-3">
            <span className="text-4xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-300 font-bold">Total XP Earned</span>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-4 bg-stone-50/50 px-4 py-2 rounded-full border border-stone-100">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">Auto-pronounce</span>
            <button onClick={() => setAutoAudio(!autoAudio)} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-0.5 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-4 h-4 bg-white rounded-full transition-all shadow-sm ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      {/* Search Input & Suggestions */}
      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className="bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[120px]">
            <div className="flex-1 flex items-center px-4 md:px-10">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
                onKeyDown={handleKeyDown}
                placeholder="Summon an inscription..."
                className="w-full text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase font-medium tracking-tighter leading-none" 
              />
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-4 md:px-10 text-stone-300 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-6 h-6 md:w-12 md:h-12 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-14 md:h-14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-300 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-6 md:px-10 py-4 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-colors ${selectedIndex === idx ? 'bg-stone-50 border-l-[4px] border-l-[#7c1a1a]' : 'border-l-[4px] border-l-transparent'}`}
               >
                 <div className="flex items-center gap-4">
                    {s.source === 'local' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-[#7c1a1a]"><path d="M12 2v10l4.5 4.5"/><circle cx="12" cy="12" r="10"/></svg>
                    )}
                    {s.source === 'seed' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-stone-400"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1-2.5-2.5Z"/><path d="M8 7h6"/><path d="M8 11h8"/></svg>
                    )}
                    {s.source === 'global' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-[#7c1a1a] opacity-80 animate-pulse"><circle cx="12" cy="12" r="10"/><path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"/><path d="M2 12h20"/></svg>
                    )}
                    <span className={`serif text-lg md:text-xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 </div>
                 <span className={`text-[8px] md:text-[10px] uppercase tracking-widest font-black transition-colors ${s.source === 'global' ? 'text-[#7c1a1a]' : 'text-stone-300'}`}>
                   {s.source === 'local' ? 'Personal Memory' : s.source === 'seed' ? 'Lexicon Scribe' : 'Global Discovery'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[50px]">
        {loading && <div className="bg-white border border-stone-100 p-8 md:p-12 animate-pulse space-y-12 rounded-sm"><div className="h-12 w-48 bg-stone-50" /></div>}
        {result && !loading && <ResultCard entry={result} />}
      </div>

      {/* Footer History Section */}
      <div className="pt-16 md:pt-24 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[3px] border-[#7c1a1a] pl-6 md:pl-8 py-1">
            <h2 className="text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[9px] uppercase tracking-[0.1em] font-medium">Recently unearthed insights</p>
          </div>
          <button onClick={onStartArena} className="group relative bg-[#7c1a1a] text-white px-8 md:px-10 py-4 flex items-center gap-4 shadow-lg hover:shadow-[#7c1a1a]/20 hover:-translate-y-1 transition-all rounded-sm w-full sm:w-auto justify-center">
            <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.4em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;

export type Language = 'German' | 'Uzbek' | 'English' | 'Russian';

export interface SemanticVariation {
  text: string;
  confidence: number;
  source: 'human' | 'ai';
}

export interface LiteraryReference {
  text: string;
  translation?: string;
  source: string;
  author?: string;
}

export interface Idiom {
  text: string;
  translation: string;
  explanation: string;
  type: 'greeting' | 'proverb' | 'historical' | 'general';
}

export interface LexicalEntry {
  id: string;
  term: string;
  lemma?: string;
  inflection?: string;
  normalizedTerm: string;
  mainTranslation: string;
  sourceLang: Language;
  targetLang: Language;
  sourceLevel?: string;
  targetLevel?: string;

  // 🔬 Philological Analysis
  philology: {
    etymology: string;
    historicalNotes?: string;
    inflectionNotes?: string;
    partOfSpeech: string;
    gender?: string;
    plural?: string;
  };

  // 🌍 Cultural / Language Context
  culture: {
    usage: string;
    register: 'formal' | 'informal' | 'neutral';
    notes: string;
  };

  // 📖 Lexical Relations
  synonyms: string[];

  // 🔁 Semantic Variations (Target Language)
  variations: SemanticVariation[];

  // 📚 Literary Manifestations
  literature: LiteraryReference[];

  // 🗣 Idioms & Fixed Expressions
  idioms: Idiom[];

  timestamp: number;
  isPreinstalled?: boolean;
}

export interface UserProfile {
  username: string;
  firstName?: string;
  lastName?: string;
  telegramId?: number;
  phoneNumber?: string;
  languageCode?: string;
  xp: number;
  rank: string;
  searchCount: number;
  arenaWins: number;
  accuracy: number;
  streak: number;
}

export enum AppMode {
  DICTIONARY = 'DICTIONARY',
  ARENA = 'ARENA',
  ARCHIVE = 'ARCHIVE'
}

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { fetchProfile, upsertProfile } from './services/supabase';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);

  const [deviceId] = useState(() => {
    let id = localStorage.getItem('lexDeviceId');
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem('lexDeviceId', id);
    }
    return id;
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    setIsSyncing(true);
    try {
      await upsertProfile(deviceId, newProfile);
    } finally {
      setIsSyncing(false);
    }
  }, [deviceId]);

  useEffect(() => {
    const hydrate = async () => {
      // Load local history
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      let currentProfile = profile;

      // Telegram init - Extract all available data
      if ((window as any).Telegram?.WebApp) {
        const tg = (window as any).Telegram.WebApp;
        tg.ready();
        tg.expand();

        const tgUser = tg.initDataUnsafe?.user;
        if (tgUser) {
          currentProfile = {
            ...currentProfile,
            username: tgUser.username || currentProfile.username,
            firstName: tgUser.first_name,
            lastName: tgUser.last_name,
            telegramId: tgUser.id,
            languageCode: tgUser.language_code,
          };
        }
      }

      // Load cloud profile to merge with local/TG data
      const cloudProfile = await fetchProfile(deviceId);
      if (cloudProfile) {
        // Prioritize XP and stats from cloud, but keep TG identity
        currentProfile = {
          ...cloudProfile,
          username: currentProfile.username,
          firstName: currentProfile.firstName,
          lastName: currentProfile.lastName,
          telegramId: currentProfile.telegramId,
          languageCode: currentProfile.languageCode,
        };
      }

      setProfile(currentProfile);
      syncProfile(currentProfile);
    };
    hydrate();
  }, [deviceId]);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 50);
    });

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const handleArenaResult = (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = (correctCount / totalQuestions) * 100;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  const navigateToDictionary = () => {
    setMode(AppMode.DICTIONARY);
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 py-10 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-6">
          <span 
            onClick={navigateToDictionary}
            className="text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              The Polyglot Insight Engine
            </span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival philology & context
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-6 md:gap-10 text-[9px] md:text-[10px] uppercase tracking-[0.2em] md:tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={navigateToDictionary} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            The Arena
          </button>
          <button 
            onClick={() => setMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-12 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-6 text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-4">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className="text-stone-200 hidden md:block">/</span>
             <span className={`flex items-center gap-1 ${isSyncing ? 'text-stone-300 animate-pulse' : 'text-[#7c1a1a]'}`}>
               {isSyncing ? 'Syncing...' : 'Cloud Synced'}
             </span>
          </div>
          <div className="flex items-center gap-4 md:gap-8 overflow-x-auto w-full md:w-auto justify-center md:justify-end">
            <span className="flex items-center gap-2 whitespace-nowrap">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              {profile.rank}
            </span>
            <span className="text-stone-900 whitespace-nowrap">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300 whitespace-nowrap">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  // Handle Dynamic Suggestions Update with Hybrid Ranking
  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        // 1. Fetch from Local History
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        // 2. Fetch from Seed Archive
        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        // 3. Fetch from Supabase Global Archive
        const globalTerms = await fetchSuggestions(query, sourceLang);
        const globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));

        // Combine with specific quota to ensure Global visibility
        const combined = [
          ...localMatches.slice(0, 3),
          ...seedMatches.slice(0, 2),
          ...globalMatches.filter(gm => !localMatches.some(lm => lm.term.toLowerCase() === gm.term.toLowerCase()))
        ].slice(0, 10);

        const unique = combined.filter((v, i, a) => a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = (lang: Language) => {
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    if (autoAudio) speak(cleanQuery, sourceLang);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      setQuery(localHit.term);
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        setQuery(globalHit.term);
        onEntrySaved(globalHit);
        setLoading(false);
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      setQuery(finalEntry.term);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = () => {
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-8 md:space-y-12 max-w-7xl mx-auto">
      {/* Header Info - XP now visible on mobile */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="space-y-2 border-l-[3px] border-[#7c1a1a] pl-6 block">
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
          <div className="flex items-baseline gap-3">
            <span className="text-3xl md:text-4xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-300 font-bold">Total XP Earned</span>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-4 bg-stone-50/50 px-4 py-2 rounded-full border border-stone-100">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">Auto-pronounce</span>
            <button onClick={() => setAutoAudio(!autoAudio)} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-0.5 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-4 h-4 bg-white rounded-full transition-all shadow-sm ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      {/* Search Input & Suggestions */}
      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className="bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[120px]">
            <div className="flex-1 flex items-center px-4 md:px-10">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
                onKeyDown={handleKeyDown}
                placeholder="Summon an inscription..."
                className="w-full text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase font-medium tracking-tighter leading-none" 
              />
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-4 md:px-10 text-stone-300 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-6 h-6 md:w-12 md:h-12 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-14 md:h-14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-300 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-6 md:px-10 py-4 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-colors ${selectedIndex === idx ? 'bg-stone-50 border-l-[4px] border-l-[#7c1a1a]' : 'border-l-[4px] border-l-transparent'}`}
               >
                 <div className="flex items-center gap-4">
                    {s.source === 'local' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-[#7c1a1a]"><path d="M12 2v10l4.5 4.5"/><circle cx="12" cy="12" r="10"/></svg>
                    )}
                    {s.source === 'seed' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-stone-400"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1-2.5-2.5Z"/><path d="M8 7h6"/><path d="M8 11h8"/></svg>
                    )}
                    {s.source === 'global' && (
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-[#7c1a1a] opacity-80 animate-pulse"><circle cx="12" cy="12" r="10"/><path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"/><path d="M2 12h20"/></svg>
                    )}
                    <span className={`serif text-lg md:text-xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 </div>
                 <span className={`text-[8px] md:text-[10px] uppercase tracking-widest font-black transition-colors ${s.source === 'global' ? 'text-[#7c1a1a]' : 'text-stone-300'}`}>
                   {s.source === 'local' ? 'Personal Memory' : s.source === 'seed' ? 'Lexicon Scribe' : 'Global Discovery'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[50px]">
        {loading && <div className="bg-white border border-stone-100 p-8 md:p-12 animate-pulse space-y-12 rounded-sm"><div className="h-12 w-48 bg-stone-50" /></div>}
        {result && !loading && <ResultCard entry={result} />}
      </div>

      {/* Footer History Section */}
      <div className="pt-16 md:pt-24 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[3px] border-[#7c1a1a] pl-6 md:pl-8 py-1">
            <h2 className="text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[9px] uppercase tracking-[0.1em] font-medium">Recently unearthed insights</p>
          </div>
          <button onClick={onStartArena} className="group relative bg-[#7c1a1a] text-white px-8 md:px-10 py-4 flex items-center gap-4 shadow-lg hover:shadow-[#7c1a1a]/20 hover:-translate-y-1 transition-all rounded-sm w-full sm:w-auto justify-center">
            <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.4em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

